      {
        "question": "If the distance between two point charges is doubled, the force becomes:",
        "answer": "C. One-fourth"
      },
      {
        "question": "Which of the following is true about electric field lines?",
        "answer": "C. They are closer where the field is stronger."
      }
    ]
  },
  "topicCoverage": []
